#include <stdio.h>
#include <stdlib.h>
#include <math.h>

// Structure to represent a data point
typedef struct {
 double x;
 double y;
} Point;

// Function to calculate the Euclidean distance between two points
 double distance(Point p1, Point p2) {
 return sqrt(pow(p1.x - p2.x, 2) + pow(p1.y - p2.y, 2));
}

int main() {
 // Generate sample data
 Point data[100];
 for (int i = 0; i < 100; i++) {
 data[i].x = rand() / (double) RAND_MAX;
 data[i].y = rand() / (double) RAND_MAX;
 }

 // Create an array to store the cluster assignments
 int labels[100];

 // Initialize k centroids randomly
 Point centroids[3];
 for (int i = 0; i < 3; i++) {
 centroids[i].x = rand() / (double) RAND_MAX;
 centroids[i].y = rand() / (double) RAND_MAX;
 }

 // Assign each data point to the closest centroid
 for (int i = 0; i < 100; i++) {
 double min_distance = INFINITY;
 int closest_centroid = -1;
 for (int j = 0; j < 3; j++) {
 double distance_ij = distance(data[i], centroids[j]);
 if (distance_ij < min_distance) {
 min_distance = distance_ij;
 closest_centroid = j;
 }
 }
 labels[i] = closest_centroid;
 }

 // Update centroids as the mean of all data points assigned to each cluster
 for (int i = 0; i < 3; i++) {
 double sum_x = 0;
 double sum_y = 0;
 int count = 0;
 for (int j = 0; j < 100; j++) {
 if (labels[j] == i) {
 sum_x += data[j].x;
 sum_y += data[j].y;
 count++;
 }
 }
 if (count > 0) {
 centroids[i].x = sum_x / count;
 centroids[i].y = sum_y / count;
 }
 }

 // Print the cluster assignments and centroids
 for (int i = 0; i < 100; i++) {
 printf("%d ", labels[i]);
 }
 printf("\n");
 for (int i = 0; i < 3; i++) {
 printf("(%f, %f) ", centroids[i].x, centroids[i].y);
 }
 printf("\n");

 return 0;
}
